const allItems = $input.all();

const results = allItems.map(item => {
  const output = item.json.output ?? '';
  const firstLine = output.split('\n')[0].trim();

  let tagsPart = firstLine;
  let customerMessage = output;

  // Nếu có tag hợp lệ
  if (firstLine.startsWith('[')) {
    tagsPart = firstLine;
    customerMessage = output.split('\n').slice(1).join('\n').trim();
  } else {
    // fallback
    tagsPart = '[GENERAL]';
  }

  const parts = tagsPart.split('|').map(p => p.trim());

  const convId = $('Webhook').first().json.body?.conversation?.id
              ?? $('Webhook').first().json.body?.id
              ?? '';

  // Time VN
  const now = new Date();
  const vnTime = new Date(now.getTime() + 7 * 60 * 60 * 1000);
  const timestamp = vnTime.toISOString()
                          .replace('T', ' ')
                          .replace(/\.\d+Z$/, '');

  // ===== NEW LOGIC PARSE =====
  const tag = parts[0] ?? 'UNKNOWN';

  let check_in = '';
  let check_out = '';
  let room_type = '';
  let room = '';
  let service_type = '';
  let detail = '';
  let name = '';
  let phone = '';
  let email = '';
  let reason = '';

  if (tag === '[BOOK]') {
    check_in = parts[1] ?? '';
    check_out = parts[2] ?? '';
    room_type = parts[3] ?? '';
  } 
  else if (tag === '[CONFIRM]') {
    check_in = parts[1] ?? '';
    check_out = parts[2] ?? '';
    room_type = parts[3] ?? '';
    name = parts[4] ?? '';
    phone = parts[5] ?? '';
    email = parts[6] ?? '';
  } 
  else if (tag === '[SERVICE]') {
    room = parts[1] ?? '';
    service_type = parts[2] ?? '';
    detail = parts[3] ?? '';
  } 
  else if (tag === '[HELP]') {
    room = parts[1] ?? '';
    detail = parts[2] ?? '';
  } 
  else if (tag === '[CANCEL]') {
    phone = parts[1] ?? '';
    reason = parts[2] ?? '';
  } 
  else {
    // GENERAL hoặc fallback
    detail = parts.slice(1).join(' ');
  }

  return {
    json: {
      timestamp        : timestamp,
      conversation_id  : convId,
      tag              : tag,

      check_in         : check_in,
      check_out        : check_out,
      room_type        : room_type,

      room             : room,
      service_type     : service_type,
      detail           : detail,

      name             : name,
      phone            : phone,
      email            : email,
      reason           : reason,

      status           : 'Mới',

      output           : output,
      customer_message : customerMessage
    }
  };
});

return results;

const data = $('Extract_request_customer').first().json;
return {
  json: {
    tag       : data.tag ?? '',
    check_in  : data.check_in ?? '',
    check_out : data.check_out ?? '',
    room_type : data.room_type ?? 'any',
  }
};

const bookingInfo = $('Extract_Book_Info').first().json;

// Đọc từ 2 nguồn
const roomList = $('Read_RoomList').all().map(r => r.json);
const bookings = $input.all().map(r => r.json);

// ===== 1. Chuẩn hóa ngày =====
const checkInStr  = bookingInfo.check_in;
const checkOutStr = bookingInfo.check_out;
const checkIn  = checkInStr  ? new Date(checkInStr  + 'T00:00:00') : new Date('');
const checkOut = checkOutStr ? new Date(checkOutStr + 'T00:00:00') : new Date('');

if (isNaN(checkIn.getTime()) || isNaN(checkOut.getTime())) {
  return [{ json: {
    available      : false,
    available_rooms: '',
    room_id        : '',
    check_in       : checkInStr,
    check_out      : checkOutStr,
    room_type      : bookingInfo.room_type ?? '',
    next_available : 'Vui lòng cung cấp ngày check-in và check-out cụ thể',
    stay_length    : 0
  }}];
}

// ===== 2. Normalize helper =====
const norm = str => (str ?? '').toLowerCase().trim()
  .replace(/\s+/g, ' ').normalize('NFC');

// ===== 3. ROOM_ALIASES: mapping tên phòng từ AI prompt sang tên trong Sheet =====
const ROOM_ALIASES = {
  'phòng giường đôi': 'phòng giường đơn',
  'phòng 4 người': 'phòng giường đôi',
  'phòng gia đình': 'phòng gia đình',
};

// ===== 4. Đọc loại phòng hợp lệ từ Sheet 1 =====
const validRoomTypes = [
  ...new Set(roomList.map(r => norm(r['Loại phòng'])).filter(Boolean))
];

// ===== 5. Tìm loại phòng khớp với AI output =====
const rawRoomType = norm(bookingInfo.room_type ?? '');

// Thử alias trước, nếu không có thì fuzzy match
const aliasedType = ROOM_ALIASES[rawRoomType] ?? rawRoomType;

const roomType = validRoomTypes.find(valid => {
  if (valid === aliasedType) return true;
  if (valid === rawRoomType) return true;
  if (valid.includes(aliasedType)) return true;
  if (aliasedType.includes(valid)) return true;
  return false;
}) ?? aliasedType;

const filterByType = roomType !== 'any' && roomType !== '';

// ===== 6. Số đêm khách muốn ở =====
const stayLength = Math.round(
  (checkOut - checkIn) / (1000 * 60 * 60 * 24)
);

// ===== 7. Lấy danh sách phòng vật lý từ Sheet 1 (Danh_Sach_Phong) =====
// Sheet 1 cột 'Số phòng'
const allRoomsOfType = roomList
  .filter(r => !filterByType || norm(r['Loại phòng']) === roomType)
  .map(r => String(r['Số phòng']))
  .filter(Boolean);

// ===== 8. Safety check =====
if (filterByType && allRoomsOfType.length === 0) {
  return [{ json: {
    available      : false,
    available_rooms: '',
    room_id        : '',
    check_in       : checkInStr,
    check_out      : checkOutStr,
    room_type      : bookingInfo.room_type,
    next_available : 'Không tìm thấy loại phòng này trong hệ thống',
    stay_length    : stayLength
  }}];
}

// ===== 9. Tìm phòng bị block từ Sheet 2 (Danh_Sach_Dat_Phong) =====
// Sheet 2 cột 'Số phòng'
const bookedRoomIds = new Set(
  bookings.filter(b => {
    const bIn  = b['Check-in']  ? new Date(b['Check-in']  + 'T00:00:00') : null;
    const bOut = b['Check-out'] ? new Date(b['Check-out'] + 'T00:00:00') : null;
    if (!bIn || !bOut) return false;

    const overlap   = checkIn < bOut && checkOut > bIn;
    const typeMatch = !filterByType || norm(b['Loại phòng']) === roomType;
    const status    = norm(b['Tình trạng'] ?? '');
    const isActive  = ['pending', 'confirmed', 'check-in', 'checked_in',
                       'đã cọc', 'đang ở'].includes(status);
    return overlap && typeMatch && isActive;
  }).map(b => String(b['Số phòng']))
);

// ===== 10. Phòng còn trống =====
const availableRooms = allRoomsOfType.filter(id => !bookedRoomIds.has(id));

// ===== 11. Gap Finder nếu hết phòng =====
let nextAvailable = '';

if (availableRooms.length === 0) {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  // Nhóm booking active theo Số phòng
  const activeByRoom = {};
  bookings.forEach(b => {
    const typeMatch = !filterByType || norm(b['Loại phòng']) === roomType;
    const status    = norm(b['Tình trạng'] ?? '');
    const isActive  = ['pending', 'confirmed', 'check-in', 'checked_in',
                       'đã cọc', 'đang ở'].includes(status);
    if (!typeMatch || !isActive) return;

    const bIn  = b['Check-in']  ? new Date(b['Check-in']  + 'T00:00:00') : null;
    const bOut = b['Check-out'] ? new Date(b['Check-out'] + 'T00:00:00') : null;
    if (!bIn || !bOut) return;

    const rid = String(b['Số phòng']);
    if (!activeByRoom[rid]) activeByRoom[rid] = [];
    activeByRoom[rid].push({ in: bIn, out: bOut });
  });

  // Tìm gap sớm nhất đủ stayLength đêm cho từng phòng
  // Bắt đầu tìm từ ngày checkout khách yêu cầu (không tìm ngày trước đó)
  let earliestGap = null;
  const searchStart = new Date(Math.max(today.getTime(), checkOut.getTime()));

  for (const rid of allRoomsOfType) {
    const segments = (activeByRoom[rid] ?? [])
      .sort((a, b) => a.in - b.in);

    let cursor = new Date(searchStart);

    for (const seg of segments) {
      if (seg.out <= cursor) continue; // booking đã qua cursor, bỏ qua
      if (seg.in > cursor) {
        const gapDays = Math.round((seg.in - cursor) / (1000 * 60 * 60 * 24));
        if (gapDays >= stayLength) {
          if (!earliestGap || cursor < earliestGap) earliestGap = new Date(cursor);
          break;
        }
      }
      // Đẩy cursor qua booking này
      if (seg.out > cursor) cursor = new Date(seg.out);
    }

    // Sau tất cả booking → trống vô hạn
    if (!earliestGap || cursor < earliestGap) earliestGap = new Date(cursor);
  }

  nextAvailable = earliestGap
    ? earliestGap.toISOString().split('T')[0]
    : 'Liên hệ để biết thêm';
}


// ===== 12. Return =====
const firstAvailableRoomId = availableRooms[0] ?? '';

return [{ json: {
  available       : availableRooms.length > 0,
  available_rooms : availableRooms.join(', '),
  room_id         : firstAvailableRoomId,
  check_in        : checkInStr,
  check_out       : checkOutStr,
  room_type       : bookingInfo.room_type,
  next_available  : nextAvailable,
  stay_length     : stayLength
}}];

