// Đọc dữ liệu phòng lấy từ sheet
const roomData = $input.first()?.json; 
const tagData = $('Extract_request_customer').first().json; // Dữ liệu khách nhập

// 1. Phân tích xem khách có gõ bừa số phòng không? (ví dụ tìm không thấy phòng 999)
if (!roomData) {
  return [{
    json: {
      accept: false,
      reply_msg: "Dạ em kiểm tra hệ thống không thấy số phòng này. Anh/chị xem lại có nhầm số phòng không ạ! 😅"
    }
  }];
}

// 2. Nếu tìm thấy phòng, ép chữ về chữ thường để xét điều kiện
const status = (roomData['Tình trạng'] || '').toLowerCase().trim();

// 3. Xét luật: Nếu phòng Đang TRỐNG hoặc khách CHƯA CHECK-IN (chỉ mới cọc) -> TỪ CHỐI
if (status === 'trống' || status === 'chờ xếp (trống)' || status === 'chờ khách cọc' || status === 'đã cọc') {
  return [{
    json: {
      accept: false,
      reply_msg: "Dạ hệ thống báo phòng này hiện phòng trống. Anh/chị hãy kiểm tra lại số phòng ạ? "
    }
  }];
}

// 4. Nếu phòng ĐANG CÓ NGƯỜI Ở -> DUYỆT!
return [{
  json: {
    accept: true,
    // Thông tin này cần để truyền cho nút Lưu Sheet gốc của bạn
    timestamp: tagData.timestamp,
    conversation_id: tagData.conversation_id,
    room: tagData.room,
    tag: tagData.tag,
    service_type: tagData.service_type,
    detail: tagData.detail,
    reply_msg: "Dạ em đã ghi nhận yêu cầu phục vụ của mình rồi ạ. Xin anh/chị chờ một chút xíu nhé! "
  }
}];

