// Lấy message_id từ webhook
const msgId = $input.item.json.body?.id 
           ?? $input.item.json.body?.message?.id 
           ?? '';

// Dùng static variable để nhớ message đã xử lý
const processed = $getWorkflowStaticData('global');
if (!processed.seen) processed.seen = {};

// Nếu đã xử lý message này → dừng
if (processed.seen[msgId]) {
  return []; // trả rỗng = dừng flow
}

// Đánh dấu đã xử lý
processed.seen[msgId] = Date.now();

// Dọn cache cũ (giữ 100 message gần nhất)
const keys = Object.keys(processed.seen);
if (keys.length > 100) {
  keys.sort((a, b) => processed.seen[a] - processed.seen[b]);
  for (let i = 0; i < keys.length - 100; i++) {
    delete processed.seen[keys[i]];
  }
}

return [$input.item];

